// CODE_FIND_EXPIRED — Run Once for All Items
const MAX_DAYS=30; // <-- troque para 0 para TESTAR (trata tudo como expirado)
const now=Date.now();
const out=[];
for(const it of $input.all()){
  const r=it.json;
  if(String(r.publication_status||'').toLowerCase()!=='published')continue;
  const pub=Date.parse(r.published_at||'');
  if(Number.isNaN(pub))continue;
  if((now-pub)/(24*3600*1000) < MAX_DAYS)continue;
  out.push({json:{
    news_id:r.news_id, headline_oria:r.headline_oria||'', summary_oria:r.summary_oria||'',
    slug:r.slug||'', file_path:r.file_path||'', source_url:r.source_url||'',
    source_name:r.source_name||'', category:r.category||'', published_at:r.published_at||'',
    commit_msg:'expire: remove '+(r.file_path||'')
  }});
}
return out;

// CODE_BUILD_EXPIREDROW — recupera dados do CODE_FIND_EXPIRED (GitHub troca o item)
const idx = $itemIndex;
let j = {};
try { j = $('CODE_FIND_EXPIRED').all()[idx].json; } catch (e) { j = $json; }

const b = new Date(Date.now() - 3 * 3600 * 1000);
const p = (n) => String(n).padStart(2, '0');
const data = b.getUTCFullYear() + '-' + p(b.getUTCMonth() + 1) + '-' + p(b.getUTCDate()) + ' ' + p(b.getUTCHours()) + ':' + p(b.getUTCMinutes()) + ':' + p(b.getUTCSeconds());

const obj = {};
obj.news_id = j.news_id;
obj.headline_oria = j.headline_oria;
obj.summary_oria = j.summary_oria;
obj.slug = j.slug;
obj.file_path = j.file_path;
obj.source_url = j.source_url;
obj.source_name = j.source_name;
obj.category = j.category;
obj.published_at = j.published_at;
obj.expired_at = data;
return { json: obj };

// CODE_MARK_EXPIRED — recupera news_id do CODE_FIND_EXPIRED
const idx = $itemIndex;
let j = {};
try { j = $('CODE_FIND_EXPIRED').all()[idx].json; } catch (e) { j = $json; }

const b = new Date(Date.now() - 3 * 3600 * 1000);
const p = (n) => String(n).padStart(2, '0');
const data = b.getUTCFullYear() + '-' + p(b.getUTCMonth() + 1) + '-' + p(b.getUTCDate()) + ' ' + p(b.getUTCHours()) + ':' + p(b.getUTCMinutes()) + ':' + p(b.getUTCSeconds());

const obj = {};
obj.news_id = j.news_id;
obj.publication_status = 'expired';
obj.expired_at = data;
return { json: obj };

// KEYWORD_PENEIRA v3 (intermediária) — corta lixo seguro; deixa dúvidas (JCP/recompra/tarifa/macro) para o LLM
const norm = (s) => { s = ' ' + String(s||'').toLowerCase(); s = s.normalize('NFD').replace(/[\u0300-\u036f]/g,''); s = s.replace(/[^a-z0-9 ]+/g,' ').replace(/\s+/g,' ').trim(); return ' ' + s + ' '; };
const has = (t, w) => t.indexOf(' ' + w + ' ') !== -1;

const L = {
  LIXO: ['senado','senador','deputado','congresso','stf','supremo','gilmar','lula','bolsonaro','planalto','pec','cpi','partido','policia federal','propina','vereador','prefeito','governador','ministro','premie','guerra','tropas','israel','libano','hamas','ucrania','russia','vance','netanyahu','trump','putin','copa do mundo','futebol','messi','mbappe','selecao','jogador','fifa','taylor swift','novela','bbb','filme','cinema','gta','xbox','console','windows','menopausa','como sacar','dia de sorte','lotofacil','mega sena'],
  DESASTRE: ['terremoto','terremotos','tsunami','enchente','furacao','vulcao','desabamento','magnitude'],
  CULTURA: ['restaurante','restaurantes','gastronomia','cannes lions','wsl','surf','tequila','morcegos','golfinhos','velociraptor','dinossauro','cervejaria','museu','hollywood','o urso','avatar','o que assistir','mascaras led','skincare','influencer','pacocas'],
  CIENCIA: ['cientistas','rancor','estudo revela','paleontolog','fossil','asteroide','milhoes de anos','el nino','previsao do tempo','frio e chuva','calor','verao'],
  VIAGEM: ['vai para a europa','o que fazer e evitar'],
  CRIPTO: ['bitcoin','btc','criptomoeda','cripto','ethereum','satoshi','michael saylor'],
  BOLETIM: ['ao vivo','cotacao','dolar hoje','ibovespa','dolar cai','dolar recua','dolar sobe','wall street','sp 500','s p 500','petroleo sobe','petroleo cai','after hours','taxas dos dis','di caem','di sobe','pre mercado','acumula queda','acumula alta','fecha em alta','fecha em queda','bolsas da asia','bolsas asiaticas','circuit breaker','o que move os mercados','realizacao de lucros']
};

const out = [];
for (const it of $input.all()) {
  const r = it.json;
  const t = norm((r.headline_original||'') + ' ' + (r.summary_original||''));
  const th = norm(r.headline_original||'');
  const url = String(r.source_url||'').toLowerCase();

  const checa = (arr) => { for (const w of arr) { if (has(t, norm(w).trim())) return true; } return false; };
  let lixo = false;
  for (const k of Object.keys(L)) { if (checa(L[k])) { lixo = true; break; } }
  if (!lixo && th.indexOf(' artigo ') !== -1) lixo = true;
  if (!lixo && th.indexOf(' opiniao ') !== -1) lixo = true;
  if (!lixo && url.indexOf('/esg/') !== -1) lixo = true;
  if (!lixo && url.indexOf('/carreira/') !== -1) lixo = true;
  if (!lixo && url.indexOf('/esporte/') !== -1) lixo = true;
  if (!lixo && url.indexOf('/ciencia/') !== -1) lixo = true;
  if (!lixo && url.indexOf('/mundo/') !== -1) lixo = true;
  if (!lixo && url.indexOf('/casual/') !== -1) lixo = true;

  const b = new Date(Date.now() - 3*3600*1000);
  const p = (n) => String(n).padStart(2,'0');
  const data = b.getUTCFullYear()+'-'+p(b.getUTCMonth()+1)+'-'+p(b.getUTCDate())+' '+p(b.getUTCHours())+':'+p(b.getUTCMinutes())+':'+p(b.getUTCSeconds());

  const obj = {};
  obj.news_id = r.news_id;
  obj.status = lixo ? 'rejected' : 'triagem_llm';
  obj.qa_flags = lixo ? 'rejected_keyword' : '';
  obj.updated_at = data;
  out.push({ json: obj });
}
return out;

// CODE_BUILD_MD — description curta (card) + summary_full longo (pagina)
const now = new Date();
const fmtBR = (d) => {
  const dt = d ? new Date(d) : new Date();
  if (isNaN(dt.getTime())) return '';
  const b = new Date(dt.getTime() - 3 * 3600 * 1000);
  const p = (n) => String(n).padStart(2, '0');
  return b.getUTCFullYear() + '-' + p(b.getUTCMonth() + 1) + '-' + p(b.getUTCDate()) + ' ' + p(b.getUTCHours()) + ':' + p(b.getUTCMinutes()) + ':' + p(b.getUTCSeconds());
};
const dateOnly = (d) => fmtBR(d).slice(0, 10);

const j = $json;
const slugify = (s) => String(s || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9\s-]/g, '').trim().replace(/\s+/g, '-').slice(0, 70).replace(/-+$/g, '').replace(/^-+/g, '');

// curto para o card: 1a frase ate ~180
const cortaCurto = (raw) => {
  let t = String(raw || '').replace(/\s+/g, ' ').trim();
  if (t.length <= 180) return t;
  const janela = t.slice(0, 200);
  const re = /\.(\s|$)/g; let m, corte = -1;
  while ((m = re.exec(janela)) !== null) {
    const pos = m.index;
    const antes = pos > 0 ? janela.charAt(pos - 1) : '';
    const depois = pos + 2 < janela.length ? janela.charAt(pos + 2) : ' ';
    if (/[0-9]/.test(antes) && /[0-9]/.test(depois)) continue;
    if (pos + 1 >= 120) { corte = pos; break; }
  }
  if (corte !== -1) return janela.slice(0, corte + 1);
  let s = t.slice(0, 180); s = s.slice(0, s.lastIndexOf(' ')).trim();
  return s + '…';
};

const title = j.headline || '(sem titulo)';
const slug = slugify(title);
const resumoLongo = String(j.summary || '').replace(/\s+/g, ' ').trim(); // ja vem longo da raw_news
const resumoCurto = cortaCurto(resumoLongo);

const body = [
  resumoLongo || title,
  '',
  'Fonte: [' + (j.srcname || 'Fonte') + '](' + (j.srcurl || '') + ')'
].join('\n');

const fm = [
  '---',
  'title: ' + JSON.stringify(title),
  'slug: ' + JSON.stringify(slug),
  'description: ' + JSON.stringify(resumoCurto),
  'summary_full: ' + JSON.stringify(resumoLongo),
  'date: ' + JSON.stringify(dateOnly(now)),
  'category: ' + JSON.stringify(j.cat || 'economia'),
  'source_name: ' + JSON.stringify(j.srcname || ''),
  'source_url: ' + JSON.stringify(j.srcurl || ''),
  'image: ' + JSON.stringify(j.img || ''),
  '---', '', body, ''
].join('\n');


const filePath = 'src/content/posts/' + dateOnly(now) + '-' + slug + '.md';

const obj = {};
obj.news_id = j.news_id;
obj.slug = slug;
obj.title = title;
obj.description = resumoCurto;
obj.summary_full = resumoLongo;
obj.date = dateOnly(now);
obj.file_path = filePath;
obj.file_content = fm;  
obj.commit_msg = 'post: ' + title;
obj.srcurl = j.srcurl;
obj.srcname = j.srcname;
obj.cat = j.cat;
obj.img = j.img;
obj.updated_at = fmtBR(now);
return { json: obj };

// CODE_RAWSTATE — recupera news_id do CODE_BUILD_MD
const idx = $itemIndex;
let j = {};
try { j = $('CODE_BUILD_MD').all()[idx].json; } catch (e) { j = $json; }

const b = new Date(Date.now() - 3*3600*1000);
const p = (n)=>String(n).padStart(2,'0');
const data = b.getUTCFullYear()+'-'+p(b.getUTCMonth()+1)+'-'+p(b.getUTCDate())+' '+p(b.getUTCHours())+':'+p(b.getUTCMinutes())+':'+p(b.getUTCSeconds());

const obj = {};
obj.news_id = j.news_id;
obj.status = 'published';
obj.qa_flags = 'published';
obj.updated_at = data;
return { json: obj };

// CODE_OGIMAGE — recupera dados do CODE_TOP3 + extrai og:image + corpo do texto (até 10000)
const idx = $itemIndex;
let orig = {};
try { orig = $('CODE_TOP3').all()[idx].json; } catch (e) { orig = {}; }

const html = String($json.data || $json.body || $json.text || '');

// --- imagem (og:image) ---
let img = orig.img || '';
if (!img && html) {
  const findMeta = (key) => {
    let from = 0;
    for (let g = 0; g < 200; g++) {
      const mStart = html.indexOf('<meta', from);
      if (mStart === -1) return '';
      const mEnd = html.indexOf('>', mStart);
      if (mEnd === -1) return '';
      const tag = html.slice(mStart, mEnd + 1);
      from = mEnd + 1;
      if (tag.indexOf(key) === -1) continue;
      const cAt = tag.indexOf('content=');
      if (cAt === -1) continue;
      const q = tag.charAt(cAt + 8);
      const cEnd = tag.indexOf(q, cAt + 9);
      if (cEnd === -1) continue;
      let url = tag.slice(cAt + 9, cEnd).split('&amp;').join('&').trim();
      if (url.indexOf('http') === 0) return url;
    }
    return '';
  };
  img = findMeta('og:image') || findMeta('twitter:image') || findMeta('og:image:url') || '';
}

// --- corpo do texto (até 10000) ---
const extractBody = (raw) => {
  if (!raw) return '';
  let h = String(raw);
  h = h.replace(/<script[\s\S]*?<\/script>/gi, ' ');
  h = h.replace(/<style[\s\S]*?<\/style>/gi, ' ');
  h = h.replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ');
  h = h.replace(/<nav[\s\S]*?<\/nav>/gi, ' ');
  h = h.replace(/<header[\s\S]*?<\/header>/gi, ' ');
  h = h.replace(/<footer[\s\S]*?<\/footer>/gi, ' ');
  h = h.replace(/<aside[\s\S]*?<\/aside>/gi, ' ');
  h = h.replace(/<form[\s\S]*?<\/form>/gi, ' ');
  let paras = [];
  const re = /<p[^>]*>([\s\S]*?)<\/p>/gi;
  let m;
  while ((m = re.exec(h)) !== null) {
    let txt = m[1].replace(/<[^>]+>/g, ' ').replace(/&#?[a-z0-9]+;/gi, ' ').replace(/\s+/g, ' ').trim();
    if (txt.length >= 40) paras.push(txt);
  }
  let texto = paras.join('\n\n');
  if (texto.length < 200) {
    texto = h.replace(/<[^>]+>/g, ' ').replace(/&#?[a-z0-9]+;/gi, ' ').replace(/\s+/g, ' ').trim();
  }
  if (texto.length > 10000) texto = texto.slice(0, 10000);
  return texto;
};

let bodyText = extractBody(html);
if (!bodyText || bodyText.length < 200) bodyText = orig.summary || '';

const obj = {};
obj.news_id = orig.news_id;
obj.headline = orig.headline;
obj.summary = orig.summary;
obj.body_text = bodyText;
obj.srcname = orig.srcname;
obj.srcurl = orig.srcurl;
obj.cat = orig.cat;
obj.empresa = orig.empresa;
obj.img = img;
return { json: obj };

// CODE_PARSE_RESUMO — interpreta o resumo do GPT (formato OpenAI)
const idx = $itemIndex;
let orig = {};
try { orig = $('CODE_OGIMAGE').all()[idx].json; } catch (e) { orig = $json; }

// OpenAI: choices[0].message.content
let raw = '';
try { raw = ($json.choices && $json.choices[0] && $json.choices[0].message.content) || ''; } catch (e) { raw = ''; }

let parsed = { resumo: '', categoria: '' };
try { parsed = JSON.parse(String(raw).replace(/```json|```/g, '').trim()); } catch (e) {}

const CATS = ['insolvencia','reestruturacao','desinvestimento','ma','emissao','captacao','governanca','liquidez'];
const cat = CATS.includes(parsed.categoria) ? parsed.categoria : (orig.cat || 'economia');

// fallback: se o LLM falhar, usa o resumo cru (nunca publica vazio)
const resumo = (parsed.resumo && parsed.resumo.length > 100) ? parsed.resumo : (orig.summary || orig.headline || '');

const obj = Object.assign({}, orig);
obj.summary = resumo;   // resumo editorial do LLM (vai para o CODE_BUILD_MD)
obj.cat = cat;
return { json: obj };

// CODE_VALIDA_SCHEMA — determinístico, Run Once for Each Item
// Valida a saída da triagem (LLM 1) e decide se vai ao verificador
const idx = $itemIndex;
let orig = {};
try { orig = $('LOOP').item.json; } catch (e) { orig = {}; }

const CATS = ['insolvencia','reestruturacao','desinvestimento','ma','emissao','captacao','governanca','liquidez'];

// extrai texto da resposta (OpenAI: choices[0].message.content)
let raw = '';
try { raw = ($json.choices && $json.choices[0] && $json.choices[0].message.content) || ''; } catch (e) { raw = ''; }

// parse tolerante
let parsed = null;
try { parsed = JSON.parse(String(raw).replace(/```json|```/g,'').trim()); } catch (e) { parsed = null; }

const b = new Date(Date.now() - 3*3600*1000);
const p = (n) => String(n).padStart(2,'0');
const data = b.getUTCFullYear()+'-'+p(b.getUTCMonth()+1)+'-'+p(b.getUTCDate())+' '+p(b.getUTCHours())+':'+p(b.getUTCMinutes())+':'+p(b.getUTCSeconds());

const out = { news_id: orig.news_id, updated_at: data };

// 1) schema inválido → rejeita (sua decisão 3)
const schemaOk = parsed
  && typeof parsed.relevante === 'boolean'
  && (parsed.relevante === false || CATS.includes(parsed.categoria));

if (!schemaOk) {
  out.status = 'rejected';
  out.qa_flags = 'rejected_schema_triagem';
  out._segue = false;            // não vai ao verificador
  return { json: out };
}

// 2) triagem rejeitou → rejeita, não chama verificador (decisão 2)
if (parsed.relevante === false) {
  out.status = 'rejected';
  out.primary_tag = '';
  out.qa_flags = 'rejected_triagem: ' + (parsed.justificativa || '');
  out._segue = false;
  return { json: out };
}

// 3) válido e relevante → segue para verificação
out._segue = true;
out._cat_triagem = parsed.categoria;
out._just_triagem = parsed.justificativa || '';
// carrega o texto que o verificador vai precisar
out.headline_original = orig.headline_original || '';
out.summary_original = orig.summary_original || '';
out.raw_content = orig.raw_content || '';
return { json: out };

parameters.jsonBody:
={
  "model": "gpt-4o-mini",
  "temperature": 0,
  "response_format": { "type": "json_object" },
  "max_tokens": 200,
  "messages": [
    {
      "role": "system",
      "content": "Você é o analista de triagem da Oria Partners, boutique de assessoria financeira em reestruturação, special situations, M&A, capital structure e liquidez. Sua ÚNICA tarefa é decidir se uma notícia descreve um evento corporativo relevante e, em caso afirmativo, classificá-la em exatamente uma categoria.

DEFINIÇÃO DE RELEVANTE
Relevante = fato corporativo concreto e já ocorrido (ou formalmente anunciado) envolvendo uma empresa identificável, com consequência sobre estrutura de capital, controle, dívida, liquidez ou propriedade de ativos.

TESTE DECISIVO: algo concreto ACONTECEU com uma empresa específica (fato), ou o texto apenas INTERPRETA/OPINA sobre o cenário (tese)? Se for tese, opinião ou análise de cenário, rejeite.

NÃO é relevante (rejeite, relevante=false):
- Análise, opinião ou tese de mercado: textos que interpretam cenário, discutem tendências, avaliam riscos ou oportunidades sem um fato corporativo concreto e novo. Ex: 'por que o crédito privado está arriscado', 'o novo desafio para o investidor', 'gestores veem oportunidade em X'. Mencionar um tema relevante NÃO torna a notícia relevante se nada concreto ocorreu.
- Compilado ou boletim de múltiplos eventos: matéria que AGREGA vários fatos ou várias empresas distintas num só texto, em vez de reportar UM fato corporativo único. Sinais: 'Agenda de empresas', 'Radar do mercado', 'Destaques do dia', 'e outros destaques', 'Confira os destaques', ou vários tickers/empresas diferentes listados (ex: 'Itaú, GPS, Embraer e outros'), cada um com seu próprio assunto. Nesses casos o 'fato' é a própria lista, então rejeite. ATENÇÃO: NÃO confundir com notícia de fato único que apenas MENCIONA outras empresas de passagem (comparação, contexto de setor, cadeia). Se há um evento central claro sobre uma empresa, NÃO rejeite por esta regra.
- Troca, sucessão, nomeação ou saída de executivo (CEO, CFO, diretor) SEM mudança de controle acionário, venda ou reorganização estrutural. Sucessão de liderança, por si só, é rotina de governança e NÃO é publicável. Ex: 'empresa anuncia novo CEO', 'fundador deixa cargo e vai para o conselho' = rejeitar.
- Cotações, índices, ação sobe/cai, boletins de mercado.
- Recomendação de analista ou carteira (preço-alvo, compre, rebaixa, eleva recomendação).
- Política, esporte, entretenimento, celebridades, ciência, clima, cripto especulativa.
- Resultado trimestral sem evento estrutural.
- Lançamento de produto, expansão de varejo, abertura de loja.
- Entrevista ou opinião sem fato novo concreto.
- Projeção, rumor vago, estuda, pode vir a, sem ato formal.

PRIORIDADE GEOGRÁFICA (REGRA FORTE): Brasil primeiro. Só é relevante se o texto AFIRMA EXPLICITAMENTE elo com o Brasil: empresa brasileira, ativo/operação/subsidiária no Brasil, dívida ou credores no Brasil, ou efeito concreto e declarado sobre empresa/mercado brasileiro. Se as partes são estrangeiras e o texto NÃO menciona o Brasil de forma explícita, rejeite (relevante=false), por maior que seja o valor. NÃO presuma elo: o vínculo precisa estar escrito no texto. Texto truncado ou de paywall ('matéria exclusiva para assinantes') NÃO é motivo de rejeição por si só: avalie o elo com o Brasil no que estiver disponível, inclusive no título. Se o elo com o Brasil estiver explícito mesmo no trecho curto (ex: 'operação brasileira', 'ativo no Brasil'), avalie normalmente. Rejeite apenas se, mesmo lendo título e trecho, o elo com o Brasil não estiver afirmado. Ex: 'Schneider (França) compra Cognite (Noruega)' sem citar Brasil = rejeitar. 'Holding italiana faz IPO na Nasdaq' sem citar Brasil = rejeitar.

CATEGORIAS — escolha EXATAMENTE UMA. Quando couber em mais de uma, use a de MAIOR prioridade nesta ordem (a de cima vence):
1. insolvencia — recuperação judicial, falência, intervenção, liquidação, default declarado.
2. reestruturacao — renegociação de dívida, alongamento, turnaround, gestão de passivo em estresse, waiver, DIP.
3. desinvestimento — venda de ativo, unidade, subsidiária ou participação, sobretudo para reduzir dívida ou focar portfólio.
4. ma — aquisição, fusão, compra de controle, joint venture de capital, SEM ângulo de estresse.
5. emissao — dívida no mercado: debêntures, bonds, notes, CRI, CRA, nota promissória.
6. captacao — equity: IPO, follow-on, aporte, aumento de capital, rodada de investimento (incluindo venture capital e startups).
7. governanca — mudança de CONTROLE acionário, reorganização societária com efeito estrutural, fato relevante societário, acordo de acionistas, spinoff/cisão, OPA, fechamento de capital, saída de bolsa. NÃO inclui mera troca de executivo.
8. liquidez — gestão de caixa, linhas de crédito, reforço de liquidez sem reestruturação de passivo.

REGRA DE FRONTEIRA CRÍTICA: se há estresse financeiro (dívida em dificuldade, default iminente), use insolvencia ou reestruturacao MESMO que a notícia mencione venda de ativo ou aporte. O estresse define a categoria. Venda de ativo saudável para focar portfólio = desinvestimento. Venda de ativo para pagar credores = reestruturacao.

EXEMPLOS
Notícia: Enjoei anuncia troca de CEO; fundador vai para o conselho. -> {"relevante": false, "categoria": null, "justificativa": "Sucessão de executivo sem mudança de controle"}
Notícia: Para gestores, o CDI não paga mais o risco do crédito privado. -> {"relevante": false, "categoria": null, "justificativa": "Análise de mercado, sem fato corporativo"}
Notícia: Agenda de empresas: GPS compra Aster; Rumo assina aditivo; Nexa é abordada; Oi tem novo acionista. -> {"relevante": false, "categoria": null, "justificativa": "Compilado de múltiplos eventos e empresas"}
Notícia: Itaú, GPS, Embraer e outros destaques desta quinta (radar do dia). -> {"relevante": false, "categoria": null, "justificativa": "Boletim de destaques, múltiplos assuntos"}
