const b = new Date(Date.now() - 3 * 3600 * 1000);
const p = (n) => String(n).padStart(2, '0');
const data = b.getUTCFullYear() + '-' + p(b.getUTCMonth() + 1) + '-' + p(b.getUTCDate()) + ' ' + p(b.getUTCHours()) + ':' + p(b.getUTCMinutes()) + ':' + p(b.getUTCSeconds());
const deriveFromUrl = (url) => {
  const u = String(url || '').toLowerCase();
  if (u.indexOf('braziljournal') !== -1) return 'Brazil Journal';
  if (u.indexOf('exame') !== -1) return 'Exame';
  if (u.indexOf('neofeed') !== -1) return 'NeoFeed';
  if (u.indexOf('moneytimes') !== -1) return 'Money Times';
  if (u.indexOf('valor') !== -1) return 'Valor';
  if (u.indexOf('capitalaberto') !== -1) return 'Capital Aberto';
  if (u.indexOf('suno') !== -1) return 'Suno';
  if (u.indexOf('infomoney') !== -1) return 'InfoMoney';
  const m = u.match(/https?:\/\/(?:www\.)?([^\/.]+)/);
  if (m && m[1]) return m[1].charAt(0).toUpperCase() + m[1].slice(1);
  return 'Fonte';
};
let nome = j.srcname || j.source_name || '';
if (!nome || nome === 'unknown') nome = deriveFromUrl(j.srcurl || j.source_url || '');
// recupera o embedding do CODE_PREP casando por news_id (robusto a reordenacoes)
let emb = '';
try {
  const prep = $('CODE_PREP').all();
