    if (prep[k].json.news_id === j.news_id) { emb = prep[k].json.embedding || ''; break; }
  }
} catch (e) { emb = ''; }
const obj = {};
obj.news_id = j.news_id;
obj.headline_oria = j.title || j.headline || '';
obj.summary_oria = j.description || '';          // resumo CURTO (card)
obj.summary_full = j.summary_full || '';         // resumo LONGO (pagina)
