// CODE_PREP vE — molda item + dedup INTRA-LOTE híbrido (embedding + trigrama de título)
// dedup vs-publicado = SQL find_duplicate_v2 (DEDUP_CHECK) | Top-3 = CODE_TOP3 | consolidação diária
const canon = (u) => {
  let s = String(u || '').trim().toLowerCase();
  if (!s) return '';
  s = s.replace(/^https?:\/\//, '').replace(/^www\./, '');
  s = s.split('?')[0].split('#')[0].replace(/\/+$/, '');
  return s;
};
const getEmb = (obj) => {
  try { if (obj && obj.data && obj.data[0] && Array.isArray(obj.data[0].embedding)) return obj.data[0].embedding; } catch (e) {}
  return null;
};
const cosine = (a, b) => {
  if (!a || !b || a.length !== b.length) return 0;
  let dot = 0, na = 0, nb = 0;
  for (let i = 0; i < a.length; i++) { dot += a[i]*b[i]; na += a[i]*a[i]; nb += b[i]*b[i]; }
  if (na === 0 || nb === 0) return 0;
  return dot / (Math.sqrt(na) * Math.sqrt(nb));
};
// --- camada lexical: trigramas de título normalizado (Jaccard) ---
const normTitle = (s) => {
  s = String(s || '').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g, '');
  return s.replace(/[^a-z0-9 ]+/g, ' ').replace(/\s+/g, ' ').trim();
};
const trigrams = (s) => {
  const t = '  ' + normTitle(s) + '  ';
  const set = {};
  for (let i = 0; i < t.length - 2; i++) set[t.slice(i, i + 3)] = true;
  return Object.keys(set);
};
const jaccard = (a, b) => {
  if (!a.length || !b.length) return 0;
  const A = {}; for (const g of a) A[g] = true;
  let inter = 0; for (const g of b) if (A[g]) inter++;
  const uni = a.length + b.length - inter;
  return uni ? inter / uni : 0;
};
const SIM_COS = 0.75;   // intra-lote: cosseno >= -> duplicata (agressivo; seguro no Top-3)
const SIM_TRG = 0.50;   // intra-lote: trigrama de título >= -> duplicata
const doneUrls = {};
const seen = [];        // [{emb, tri}]
const out = [];
for (const it of $input.all()) {
  const r = it.json;
  const cu = canon(r.source_url);
  if (cu && doneUrls[cu]) continue;                 // url repetida no mesmo lote
  const emb = getEmb(r);
  const tri = trigrams(r.headline_original || '');
  let dup = false;                                  // dedup INTRA-LOTE híbrido
  for (let k = 0; k < seen.length; k++) {
    const cs = (emb && seen[k].emb) ? cosine(emb, seen[k].emb) : 0;
    const tg = jaccard(tri, seen[k].tri);
    if (cs >= SIM_COS || tg >= SIM_TRG) { dup = true; break; }
  }
  if (dup) continue;
  if (cu) doneUrls[cu] = true;
  seen.push({ emb: emb, tri: tri });
  const obj = {};
  obj.news_id = r.news_id;
  obj.headline = r.headline_original || '';
  obj.summary = r.summary_original || '';
  obj.srcname = r.source_name || '';
  obj.srcurl = r.source_url || '';
  obj.cat = r.primary_tag || 'economia';
  obj.img = r.image_url || '';
  obj.embedding = emb ? JSON.stringify(emb) : '';
  obj.relevance_score = Number(r.relevance_score || 0);   // p/ ranking Top-3 (CODE_TOP3)
  out.push({ json: obj });
}
return out;

