// CODE_RESOLVE — cruza triagem × verificação, decide approved/rejected e calcula relevance_score
let prev = {};
try { prev = $('CODE_VALIDA_SCHEMA').item.json; } catch (e) { prev = {}; }
let orig = {};
try { orig = $('LOOP').item.json; } catch (e) { orig = {}; }

const CATS = ['insolvencia','reestruturacao','desinvestimento','ma','emissao','captacao','governanca','liquidez'];

let raw = '';
try { raw = ($json.choices && $json.choices[0] && $json.choices[0].message.content) || ''; } catch (e) { raw = ''; }

let v = null;
try { v = JSON.parse(String(raw).replace(/```json|```/g,'').trim()); } catch (e) { v = null; }

const b = new Date(Date.now() - 3*3600*1000);
const p = (n) => String(n).padStart(2,'0');
const data = b.getUTCFullYear()+'-'+p(b.getUTCMonth()+1)+'-'+p(b.getUTCDate())+' '+p(b.getUTCHours())+':'+p(b.getUTCMinutes())+':'+p(b.getUTCSeconds());

const out = { news_id: prev.news_id, updated_at: data };
out._segue = true;   // chegou ao verificador => passou na triagem (auditoria coerente)

// schema do verificador inválido → rejeita (conservador)
const vOk = v && typeof v.relevante_confirmado === 'boolean';
if (!vOk) {
  out.status = 'rejected';
  out.qa_flags = 'rejected_schema_verifica';
  out.relevance_score = 0;
  return { json: out };
}

// regra 1: relevância negada = eliminatório
if (v.relevante_confirmado === false) {
  out.status = 'rejected';
  out.primary_tag = '';
  out.qa_flags = 'rejected_verifica: ' + (v.observacao || '');
  out.relevance_score = 0;
  return { json: out };
}

// regra 2: relevante confirmado → aprova; categoria do VERIFICADOR prevalece
let catFinal = CATS.includes(v.categoria_correta) ? v.categoria_correta : prev._cat_triagem;

// score composto (0-100): 0.5*core + 0.3*materialidade + 0.2*autoridade_da_fonte
const tierMap = { 'Valor':1.0,'Brazil Journal':1.0,'NeoFeed':1.0,'Exame':0.7,'Capital Aberto':0.7,'Money Times':0.4 };
const clamp = (x) => Math.max(0, Math.min(100, Number(x) || 0));
// fallback por categoria se o LLM omitir/zerar os scores (nunca deixa aprovado com score 0)
const catBase = { insolvencia:90, reestruturacao:85, desinvestimento:65, ma:60, emissao:50, captacao:50, governanca:45, liquidez:55 };
let sCore = clamp(v.score_core);
let sMat  = clamp(v.score_materialidade);
if (!(sCore > 0)) sCore = catBase[catFinal] || 50;   // relevância confirmada => score minimamente informativo
if (!(sMat  > 0)) sMat  = 50;                         // materialidade neutra na ausência de sinal
const tier  = (tierMap[orig.source_name] != null) ? tierMap[orig.source_name] : 0.4;
const score = Math.round(0.5*sCore + 0.3*sMat + 0.2*100*tier);

out.status = 'approved';
out.primary_tag = catFinal;
out.qa_flags = '';
out.relevance_score = score;
return { json: out };

// CODE_NORMALIZE — summary_original (curto ~800) + raw_content (até 4000 p/ triagem)
const now = new Date();
const nowMs = Date.now();
const CUT = 48 * 3600 * 1000;
const CAP = 75;

const fmtBR = (d) => {
  const dt = d ? new Date(d) : new Date();
  if (isNaN(dt.getTime())) return '';
  const b = new Date(dt.getTime() - 3 * 3600 * 1000);
  const p = (n) => String(n).padStart(2, '0');
  return b.getUTCFullYear() + '-' + p(b.getUTCMonth() + 1) + '-' + p(b.getUTCDate()) + ' ' + p(b.getUTCHours()) + ':' + p(b.getUTCMinutes()) + ':' + p(b.getUTCSeconds());
};

const deriveFromUrl = (url) => {
  const u = String(url || '').toLowerCase();
  if (u.indexOf('braziljournal') !== -1) return 'Brazil Journal';
  if (u.indexOf('exame') !== -1) return 'Exame';
  if (u.indexOf('neofeed') !== -1) return 'NeoFeed';
  if (u.indexOf('moneytimes') !== -1) return 'Money Times';
  if (u.indexOf('valor') !== -1) return 'Valor';
  if (u.indexOf('capitalaberto') !== -1) return 'Capital Aberto';
  if (u.indexOf('suno') !== -1) return 'Suno';
