  if (u.indexOf('investing') !== -1) return 'Investing.com';
  const m = u.match(/https?:\/\/(?:www\.)?([^\/.]+)/);
  if (m && m[1]) return m[1].charAt(0).toUpperCase() + m[1].slice(1);
  return 'Fonte';
};

// CURTO (~800) — para o card do site e a peneira keyword
const cleanLong = (raw) => {
  const alvo = 700, teto = 820, minFrase = 600;
  let t = String(raw || '');
  t = t.replace(/The post[\s\S]*?appeared first on.*$/i, '').trim();
  t = t.replace(/O post[\s\S]*?apareceu primeiro em.*$/i, '').trim();
  t = t.replace(/new TradingView[\s\S]*?\}\);?/gi, ' ');
  t = t.replace(/CONTINUA DEPOIS DO CONTEUDO[\s\S]*?PAN/gi, ' ');
  t = t.replace(/LEIA TAMBEM[\s\S]*$/i, ' ');
  t = t.replace(/Leia mais em[\s\S]*$/i, ' ');
  t = t.replace(/<[^>]+>/g, ' ');
  t = t.replace(/\[\s*(\u2026|\.\.\.)\s*\]/g, ' ');
  t = t.replace(/&#?[a-z0-9]+;/gi, ' ');
  t = t.replace(/\s+/g, ' ').trim();
  if (t.length <= alvo) {
    if (t && '.!?'.indexOf(t.charAt(t.length - 1)) === -1) t += '.';
    return t;
  }
  const janela = t.slice(0, teto);
  let corte = -1;
  const re = /\.(\s|$)/g; let m;
  while ((m = re.exec(janela)) !== null) {
    const pos = m.index;
    const antes = pos > 0 ? janela.charAt(pos - 1) : '';
    const depois = pos + 2 < janela.length ? janela.charAt(pos + 2) : ' ';
    if (/[0-9]/.test(antes) && /[0-9]/.test(depois)) continue;
    if (pos + 1 >= minFrase) { corte = pos; break; }
  }
  if (corte !== -1) return janela.slice(0, corte + 1);
  let s = t.slice(0, alvo); s = s.slice(0, s.lastIndexOf(' ')).trim();
  return s + '.';
};

// LONGO (até 4000) — só para a triagem/verificação lerem (uso interno)
const cleanRaw = (raw) => {
  const teto = 4000;
  let t = String(raw || '');
  t = t.replace(/The post[\s\S]*?appeared first on.*$/i, '').trim();
  t = t.replace(/O post[\s\S]*?apareceu primeiro em.*$/i, '').trim();
  t = t.replace(/new TradingView[\s\S]*?\}\);?/gi, ' ');
  t = t.replace(/CONTINUA DEPOIS DO CONTEUDO[\s\S]*?PAN/gi, ' ');
  t = t.replace(/LEIA TAMBEM[\s\S]*$/i, ' ');
  t = t.replace(/Leia mais em[\s\S]*$/i, ' ');
  t = t.replace(/<[^>]+>/g, ' ');
  t = t.replace(/&#?[a-z0-9]+;/gi, ' ');
  t = t.replace(/\s+/g, ' ').trim();
  if (t.length <= teto) return t;
  let s = t.slice(0, teto);
  const lastSpace = s.lastIndexOf(' ');
  if (lastSpace > teto - 200) s = s.slice(0, lastSpace);
  return s.trim();
};

const extractImg = (html) => {
  if (!html) return '';
  const s = String(html);
  let pos = 0;
  for (let guard = 0; guard < 80; guard++) {
    const tag = s.indexOf('<img', pos);
    if (tag === -1) break;
    const tagEnd = s.indexOf('>', tag);
    const imgTag = s.slice(tag, tagEnd === -1 ? tag + 600 : tagEnd + 1);
    pos = (tagEnd === -1 ? tag + 1 : tagEnd + 1);
    let url = '';
    const ssAt = imgTag.indexOf('srcset=');
    if (ssAt !== -1) {
      const q = imgTag.charAt(ssAt + 7);
      const ssEnd = imgTag.indexOf(q, ssAt + 8);
      if (ssEnd !== -1) {
        const ss = imgTag.slice(ssAt + 8, ssEnd);
        const parts = ss.split(',');
        const last = parts[parts.length - 1].trim().split(/\s+/)[0];
        if (last) url = last;
      }
    }
    if (!url) {
      const srcAt = imgTag.indexOf('src=');
      if (srcAt !== -1) {
        const q = imgTag.charAt(srcAt + 4);
        const e = imgTag.indexOf(q, srcAt + 5);
        if (e !== -1) url = imgTag.slice(srcAt + 5, e);
      }
    }
    url = String(url).split('&amp;').join('&').trim();
    if (!url) continue;
    if (url.indexOf('data:') === 0) continue;
    if (url.indexOf('http') !== 0) continue;
    const low = url.toLowerCase();
    if (low.indexOf('1x1') !== -1 || low.indexOf('pixel') !== -1 || low.indexOf('spacer') !== -1 || low.indexOf('avatar') !== -1 || low.indexOf('gravatar') !== -1) continue;
    return url;
  }
  return '';
};

const short = String(nowMs).slice(-4);

const out = [];
let i = 0;
for (const it of $input.all()) {
  const r = it.json;

  let link = '';
  if (r.link) link = String(r.link).trim();
  if (!link && r.guid) link = String(typeof r.guid === 'object' ? (r.guid['#text'] || r.guid._ || '') : r.guid).trim();
  if (!link && r.id) link = String(r.id).trim();
