try { ex = $('GS_READ_RECENT').all().map((i) => i.json); } catch (e) { ex = []; }

const seen = new Set(ex.map((r) => canon(r.source_url)).filter(Boolean));
const out = [];
for (const r of inc) {
  const c = canon(r.source_url);
  if (!c || seen.has(c)) continue;
  seen.add(c);
  out.push({ json: r });
}
return out;

// CODE_LIMPA_EMB — identifica linhas com embedding preenchido e > 3 dias, para esvaziar a celula
const rows = $input.all().map((i) => i.json);
const agora = Date.now();
const TRES_DIAS = 3 * 24 * 3600 * 1000;
const out = [];
for (let k = 0; k < rows.length; k++) {
  const r = rows[k];
  const emb = r.embedding;
  // so interessa quem tem embedding preenchido
  if (!emb || String(emb).trim() === '') continue;
  // data de publicacao
  const pub = String(r.published_at || '').slice(0, 10);
  if (!pub) continue;
  const t = new Date(pub + 'T00:00:00Z').getTime();
  if (isNaN(t)) continue;
  // mais de 3 dias -> marcar para limpar
  if (agora - t > TRES_DIAS) {
    out.push({ json: { news_id: r.news_id, embedding: '' } });
  }
}
return out;

