// CODE_DEDUP_RESOLVE — combina zona (find_duplicate_v2) + veredito do LLM (GPT-API_DEDUP)
// e define is_dup final. Entra o item mesclado por posição (MERGE_DEDUP2).
const out = [];
for (const it of $input.all()) {
  const j = it.json;
  const zone = j.zone || 'none';
  let mesmo = false;                       // veredito do LLM (só usado na zona cinzenta)
  try {
    const raw = (j.choices && j.choices[0] && j.choices[0].message.content) || '';
    const v = JSON.parse(String(raw).replace(/```json|```/g, '').trim());
    mesmo = !!(v && v.mesmo_evento === true);
  } catch (e) { mesmo = false; }
  let is_dup = false;
  if (zone === 'high') is_dup = true;       // cosseno/trigrama alto -> duplicata automática
  else if (zone === 'gray') is_dup = mesmo; // ambíguo -> o LLM decide
  else is_dup = false;                      // 'none' -> único
  out.push({ json: {
    news_id: j.news_id,
    headline: j.headline || '',
    summary: j.summary || '',
    srcname: j.srcname || '',
    srcurl: j.srcurl || '',
    cat: j.cat || 'economia',
    img: j.img || '',
    embedding: j.embedding || '',
    relevance_score: Number(j.relevance_score || 0),
    is_dup: is_dup
  }});
}
return out;

// CODE_TOP3 — consolidação diária: ranqueia os ÚNICOS por relevance_score e publica só os 3 melhores.
// Também é a âncora de recuperação por índice do CODE_OGIMAGE (ordem/contagem estáveis a jusante).
const items = $input.all().slice();
items.sort((a, b) => (Number(b.json.relevance_score || 0)) - (Number(a.json.relevance_score || 0)));
return items.slice(0, 3);

